.pub-bubble {
  position: relative;
  border-radius: 50%;
  aspect-ratio: 1 / 1;
  min-height: 180px;
  cursor: pointer;
  overflow: visible;
  transform-origin: center;
  transition: transform 220ms ease;
  outline: none;
}

.pub-bubble::before,
.pub-bubble::after {
  content: "";
  position: absolute;
  inset: -5px;
  border-radius: 50%;
  pointer-events: none;
  border: 1px solid rgba(126, 199, 255, 0.28);
  animation: bubble-pulse 3.2s ease-out infinite;
}

.pub-bubble::after {
  inset: -11px;
  opacity: 0.42;
  animation-delay: 1.4s;
}

.pub-bubble:hover {
  transform: translateY(-2px) scale(1.03);
}

.pub-bubble:focus-visible {
  box-shadow: 0 0 0 3px rgba(126, 199, 255, 0.45);
}

.pub-flip {
  position: absolute;
  inset: 0;
  border-radius: 50%;
  transform-style: preserve-3d;
  transition: transform 1000ms cubic-bezier(0.22, 0.61, 0.36, 1);
}

.pub-bubble:hover .pub-flip,
.pub-bubble.is-flipped .pub-flip {
  transform: rotateY(180deg);
}

