<script>
(function(){
  const grid = document.querySelector(".pub-grid");
  if(!grid) return;

  function setFlipped(bubble, flipped){
    bubble.classList.toggle("is-flipped", flipped);
    bubble.setAttribute("aria-pressed", flipped ? "true" : "false");
  }

  function closeOthers(current){
    grid.querySelectorAll(".pub-bubble.is-flipped").forEach((el)=>{
      if(el !== current) setFlipped(el, false);
    });
  }

  grid.addEventListener("click", (e)=>{
    const link = e.target.closest(".pub-open");
    if(link) return;
    const bubble = e.target.closest(".pub-bubble");
    if(!bubble) return;
    e.preventDefault();
    const willFlip = !bubble.classList.contains("is-flipped");
    closeOthers(bubble);
    setFlipped(bubble, willFlip);
  });

  grid.addEventListener("keydown", (e)=>{
    const bubble = e.target.closest(".pub-bubble");
    if(!bubble) return;
    if(e.key === "Enter" || e.key === " "){
      e.preventDefault();
      const willFlip = !bubble.classList.contains("is-flipped");
      closeOthers(bubble);
      setFlipped(bubble, willFlip);
    }
    if(e.key === "Escape"){
      setFlipped(bubble, false);
    }
  });

  document.addEventListener("click", (e)=>{
    if(e.target.closest(".pub-bubble")) return;
    grid.querySelectorAll(".pub-bubble.is-flipped").forEach((el)=>setFlipped(el, false));
  });
})();
</script>
